class TestNormal:

    @pytest.fixture()
    def normal(self,mu,sigma):
        params = {"mu": Parameter("μ", -999, 999, 0.1, mu),
                  "sigma": Parameter("σ", 0.1, 999, 0.1, sigma)}
        return Normal(params)

    def test_pdf(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in pdf_data:
            assert normal.pdf(x)==pytest.approx(p,4)

    def test_mini(self,normal,mu,sigma,pdf_data,cdf_data, interval_data, sym_interval_data):
        assert normal.mini==mu-5*sigma

    def test_maxi(self,normal,mu,sigma,pdf_data,cdf_data, interval_data, sym_interval_data):
        assert normal.maxi==mu+5*sigma

    def test_expectation(self,normal,mu,sigma,pdf_data,cdf_data, interval_data, sym_interval_data):
        assert normal.expectation()==mu

    def test_variance(self,normal,mu,sigma,pdf_data,cdf_data, interval_data, sym_interval_data):
        assert normal.variance()==sigma**2

    def test_xpexclusivein(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for a,b,p in sym_interval_data:
            assert normal.xpexclusivein(p)==(pytest.approx(a, 4), pytest.approx(b, 4))

    def test_xpinclusivein(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for a,b,p in sym_interval_data:
            assert normal.xpinclusivein(p)==(pytest.approx(a, 4), pytest.approx(b, 4))

    def test_pxequals(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,_ in pdf_data:
            assert normal.pxequals(x)==0

    def test_pxlessthan(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.pxlessthan(x)==pytest.approx(p,4)

    def test_pxlessthanequalto(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.pxlessthanequalto(x)==pytest.approx(p,4)

    def test_pxgreaterthan(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.pxgreaterthan(x)==pytest.approx(1-p,4)

    def test_pxgreaterthanequalto(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.pxgreaterthanequalto(x)==pytest.approx(1-p,4)

    def test_pxinclusivein(self, normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for a,b,p in interval_data:
            assert normal.pxinclusivein(a,b)==pytest.approx(p, 4)

    def test_pxexclusivein(self, normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for a,b,p in interval_data:
            assert normal.pxexclusivein(a,b)==pytest.approx(p, 4)

    def test_xplessthan(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.xplessthan(p)==pytest.approx(x, 4)

    def test_xplessthanequalto(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.xplessthanequalto(p)==pytest.approx(x, 4)

    def test_xpgreaterthan(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.xpgreaterthan(1-p)==pytest.approx(x, 4)

    def test_xpgreaterthanequalto(self,normal,pdf_data,cdf_data, interval_data, sym_interval_data):
        for x,p in cdf_data:
            assert normal.xpgreaterthanequalto(1-p)==pytest.approx(x, 4)
